    decoded_instruction_t next_instruction;
    int cycle;
    logic scoreboard_can_issue;
    logic will_issue;
    logic writeback_en;
    logic wb_writeback_vector;
    register_idx_t wb_writeback_reg;
    logic rollback_en;
    pipeline_sel_t wb_rollback_pipeline;

