#include "asm_macros.h"

// Scalar/scalar operation
.macro test_sss operation, result, operand1, operand2
                li s0, \operand1
                li s1, \operand2
                \operation s2, s0, s1
                li s3, \result
                cmpeq_i s4, s2, s3
                bnz s4, 1f
                call fail_test
1:
.endmacro

// Unary scalar operation
.macro test_ss operation, result, operand1
                li s0, \operand1
                \operation s2, s0
                li s3, \result
                cmpeq_i s4, s2, s3
                bnz s4, 1f
                call fail_test
1:
.endmacro

